namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // Start transaction for atomicity
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    bool success = true;

    // Iterate through each document ID and perform the update
    for (auto id : ids) {
        // Create update statement using sqlgen::update
        auto update_stmt = sqlgen::update<Document>(
            "is_deleted"_c.set(1),
            "deleted_at"_c.set(sqlgen::CURRENT_TIMESTAMP)
        ) | sqlgen::where("doc_id"_c == id);

        // Execute the update
        auto result = update_stmt(conn);
        if (!result) {
            success = false;
            break;
        }
    }

    // Commit transaction if all updates succeeded, rollback otherwise
    if (success) {
        auto commit_result = conn->commit();
        if (!commit_result) {
            success = false;
        }
    } else {
        auto rollback_result = conn->rollback();
        // Even if rollback fails, we return false since the operation failed
    }

    return success;
}

}  // namespace soft_delete_records
