  // Create temporary table and insert events
  auto create_table_sql = R"(
    CREATE TEMPORARY TABLE IF NOT EXISTS Event (
      event_id INTEGER PRIMARY KEY,
      event_name TEXT NOT NULL,
      start_time TEXT NOT NULL,
      end_time TEXT,
      created_at TEXT NOT NULL
    )
  )";

  auto create_result = conn->execute(create_table_sql);
  if (!create_result) {
    throw std::runtime_error("Failed to create table");
  }

  auto write_result = sqlgen::write(conn, events);
  if (!write_result) {
    throw std::runtime_error("Failed to write events");
  }

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<Event>(
      "event_id"_c,
      "event_name"_c,
      sqlgen::day("start_time"_c).as<"start_day">(),
      sqlgen::month("start_time"_c).as<"start_month">(),
      sqlgen::year("start_time"_c).as<"start_year">(),
      sqlgen::hour("start_time"_c).as<"start_hour">(),
      sqlgen::minute("start_time"_c).as<"start_minute">(),
      sqlgen::second("start_time"_c).as<"start_second">(),
      sqlgen::weekday("start_time"_c).as<"start_weekday">(),
      sqlgen::unixepoch("start_time"_c).as<"start_epoch">(),
      sqlgen::days_between("start_time"_c, "end_time"_c).as<"duration_days">()
  ) | sqlgen::where("end_time"_c.is_not_null());

  // Execute the query and map results
  auto result = query(conn);
  std::vector<TemporalAnalysis> analyses;

  for (auto& row : result) {
    // Extract values from the row tuple
    int event_id = std::get<0>(row);
    std::string event_name = std::get<1>(row);
    int start_day = std::get<2>(row);
    int start_month = std::get<3>(row);
    int start_year = std::get<4>(row);
    int start_hour = std::get<5>(row);
    int start_minute = std::get<6>(row);
    int start_second = std::get<7>(row);
    int start_weekday = std::get<8>(row);
    int64_t start_epoch = std::get<9>(row);
    double duration_days_value = std::get<10>(row);

    analyses.emplace_back(TemporalAnalysis{
        event_id,
        event_name,
        start_day,
        start_month,
        start_year,
        start_hour,
        start_minute,
        start_second,
        start_weekday,
        start_epoch,
        duration_days_value  // This will automatically convert to std::optional<double>
    });
  }

  return analyses;
}

