  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return JoinAnalysis{};
  }
  auto conn = conn_result.value();

  // Create tables
  auto create_dept = sqlgen::create_table<Department>;
  auto create_emp = sqlgen::create_table<Employee>;

  conn->execute(sqlgen::sqlite::to_sql(create_dept));
  conn->execute(sqlgen::sqlite::to_sql(create_emp));

  // Insert data
  if (!depts.empty()) {
    auto insert_depts = sqlgen::insert(depts);
    conn->execute(sqlgen::sqlite::to_sql(insert_depts));
  }

  if (!emps.empty()) {
    auto insert_emps = sqlgen::insert(emps);
    conn->execute(sqlgen::sqlite::to_sql(insert_emps));
  }

  // Define join condition
  auto join_condition = "department_id"_c == "department_id"_c;

  // Perform INNER JOIN
  auto inner_query = sqlgen::read<std::vector<JoinResult>> 
                   | sqlgen::inner_join<Department, "d">(join_condition)
                   | sqlgen::inner_join<Employee, "e">(join_condition);

  auto inner_result = inner_query(conn);
  if (inner_result) {
    for (auto& res : inner_result.value()) {
      JoinResult inner_jr{
          .department_name = res.department_name,
          .first_name = res.first_name,
          .last_name = res.last_name,
          .salary = res.salary
      };
      JoinAnalysis::inner_join_results.push_back(inner_jr);
    }
  }

  // Perform LEFT JOIN
  auto left_query = sqlgen::read<std::vector<JoinResult>> 
                 | sqlgen::left_join<Employee, "e">(join_condition)
                 | sqlgen::left_join<Department, "d">(join_condition);

  auto left_result = left_query(conn);
  if (left_result) {
    for (auto& res : left_result.value()) {
      JoinResult left_jr{
          .department_name = res.department_name,
          .first_name = res.first_name,
          .last_name = res.last_name,
          .salary = res.salary
      };
      JoinAnalysis::left_join_results.push_back(left_jr);
    }
  }

  // Perform RIGHT JOIN
  auto right_query = sqlgen::read<std::vector<JoinResult>> 
                 | sqlgen::right_join<Department, "d">(join_condition)
                 | sqlgen::right_join<Employee, "e">(join_condition);

  auto right_result = right_query(conn);
  if (right_result) {
    for (auto& res : right_result.value()) {
      JoinResult right_jr{
          .department_name = res.department_name,
          .first_name = res.first_name,
          .last_name = res.last_name,
          .salary = res.salary
      };
      JoinAnalysis::right_join_results.push_back(right_jr);
    }
  }

  // Perform FULL JOIN
  auto full_query = sqlgen::read<std::vector<JoinResult>> 
                 | sqlgen::full_join<Employee, "e">(join_condition)
                 | sqlgen::full_join<Department, "d">(join_condition);

  auto full_result = full_query(conn);
  if (full_result) {
    for (auto& res : full_result.value()) {
      JoinResult full_jr{
          .department_name = res.department_name,
          .first_name = res.first_name,
          .last_name = res.last_name,
          .salary = res.salary
      };
      JoinAnalysis::full_join_results.push_back(full_jr);
    }
  }

  return JoinAnalysis{
      .inner_join_results = std::move(JoinAnalysis::inner_join_results),
      .left_join_results = std::move(JoinAnalysis::left_join_results),
      .right_join_results = std::move(JoinAnalysis::right_join_results),
      .full_join_results = std::move(JoinAnalysis::full_join_results)
  };
}

}  // namespace analyze_department_employees

